     4→const updateInfiniteJournalsCache = (old, updater) => {
     5→    if (!old || !Array.isArray(old.pages)) return old;
     6→
     7→    return {
     8→        ...old,
     9→        pages: old.pages.map((page) => ({
    10→            ...page,
    11→            data: Array.isArray(page?.data) ? page.data.map(updater) : page?.data,
    12→        })),
    13→    };
    14→};
