    16→export const useBookMarkMutation = (session, userId) => {
    17→    const queryClient = useQueryClient();
    18→    return useMutation({
    19→        mutationFn: (data) => addBookmark(session?.access_token, data),
    20→
    21→        onMutate: async(data) =>{
    22→            queryClient.cancelQueries({ queryKey: ['journals'] });
    23→            const previousData = queryClient.getQueriesData({ queryKey: ['journals'] });
    24→
    25→            queryClient.setQueriesData({ queryKey: ['journals'] }, (old) => {
    26→                return updateInfiniteJournalsCache(old, (journal) => {
    27→                    if(journal.id !== data.journalId) return journal;
    28→
    29→                    const isBookmarked = journal.has_bookmarked;
    30→                    const count = journal.bookmark_count?.[0]?.count ?? 0;
    31→
    32→                    return{
    33→                        ...journal,
    34→                        has_bookmarked: !isBookmarked,
    35→                        bookmark_count: [{count: isBookmarked ? count - 1 : count + 1}]
    36→                    };
    37→                });
    38→            });
    39→
    40→            return {previousData};
    41→        },
    42→        onError: (err,data, context) =>{
    43→            context?.previousData?.forEach(([key, value]) => {
    44→                queryClient.setQueryData(key, value);
    45→            });
    46→        },
    47→        onSettled: () =>{
    48→            queryClient.invalidateQueries({ queryKey: ['journals'] });
    49→        }
    50→    })
    51→}
